#include <stdio.h>
#include <inttypes.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int64_t A, C; scanf("%" PRId64 " %" PRId64, &A, &C);
        int64_t sum = A + C;
        if (sum % 2 == 0) printf("%" PRId64 "\n", sum / 2);
        else printf("-1\n");
    }
    return 0;
}

